tool_events.output:
100→		stopc:    make(chan struct{}),
   101→	}
   102→	s.store.ReadView = &readView{s}
   103→	s.store.WriteView = &writeView{s}
   104→	if s.le != nil {
   105→		// use this store as the deleter so revokes trigger watch events
   106→		s.le.SetRangeDeleter(func() lease.TxnDelete { return s.Write(traceutil.TODO()) })
   107→	}
   108→	return s
   109→}
