   127→func (s *watchableStore) watch(key, end []byte, startRev int64, id WatchID, ch chan<- WatchResponse, fcs ...FilterFunc) (*watcher, cancelFunc) {
   128→	wa := &watcher{
   129→		key:      key,
   130→		end:      end,
   131→		startRev: startRev,
   132→		minRev:   startRev,
   133→		id:       id,
   134→		ch:       ch,
   135→		fcs:      fcs,
   136→	}
   137→
   138→	s.mu.Lock()
   139→	s.revMu.RLock()
   140→	synced := startRev > s.store.currentRev || startRev == 0
   141→	if synced {
   142→		wa.minRev = s.store.currentRev + 1
   143→		if startRev > wa.minRev {
   144→			wa.minRev = startRev
   145→		}
   146→		s.synced.add(wa)
   147→	} else {
   148→		slowWatcherGauge.Inc()
   149→		s.unsynced.add(wa)
   150→	}
   151→	s.revMu.RUnlock()
   152→	s.mu.Unlock()
   153→
   154→	watcherGauge.Inc()
   155→
   156→	return wa, func() { s.cancelWatcher(wa) }
   157→}
   158→
   159→// cancelWatcher removes references of the watcher from the watchableStore
   160→func (s *watchableStore) cancelWatcher(wa *watcher) {
   161→	for {
   162→		s.mu.Lock()
   163→		if s.unsynced.delete(wa) {
   164→			slowWatcherGauge.Dec()
   165→			watcherGauge.Dec()
   166→			break
   167→		} else if s.synced.delete(wa) {
   168→			watcherGauge.Dec()
   169→			break
   170→		} else if wa.ch == nil {
   171→			// already canceled (e.g., cancel/close race)
   172→			break
   173→		} else if wa.compacted {
   174→			watcherGauge.Dec()
   175→			break
   176→		}
   177→
   178→		if !wa.victim {
   179→			s.mu.Unlock()
   180→			panic("watcher not victim but not in watch groups")
   181→		}
   182→
   183→		var victimBatch watcherBatch
   184→		for _, wb := range s.victims {
   185→			if wb[wa] != nil {
   186→				victimBatch = wb
   187→				break
   188→			}
   189→		}
   190→		if victimBatch != nil {
   191→			slowWatcherGauge.Dec()
   192→			watcherGauge.Dec()
   193→			delete(victimBatch, wa)
   194→			break
   195→		}
   196→
   197→		// victim being processed so not accessible; retry
   198→		s.mu.Unlock()
   199→		time.Sleep(time.Millisecond)
   200→	}
   201→
   202→	wa.ch = nil
   203→	s.mu.Unlock()
   204→}
