   206→func (s *watchableStore) Restore(b backend.Backend) error {
   207→	s.mu.Lock()
   208→	defer s.mu.Unlock()
   209→	err := s.store.Restore(b)
   210→	if err != nil {
   211→		return err
   212→	}
   213→
   214→	for wa := range s.synced.watchers {
   215→		wa.restore = true
   216→		s.unsynced.add(wa)
   217→	}
   218→	s.synced = newWatcherGroup()
   219→	return nil
   220→}
