   222→// syncWatchersLoop syncs the watcher in the unsynced map every 100ms.
   223→func (s *watchableStore) syncWatchersLoop() {
   224→	defer s.wg.Done()
   225→
   226→	delayTicker := time.NewTicker(watchResyncPeriod)
   227→	defer delayTicker.Stop()
   228→	var evs []mvccpb.Event
   229→
   230→	for {
   231→		s.mu.RLock()
   232→		st := time.Now()
   233→		lastUnsyncedWatchers := s.unsynced.size()
   234→		s.mu.RUnlock()
   235→
   236→		unsyncedWatchers := 0
   237→		if lastUnsyncedWatchers > 0 {
   238→			unsyncedWatchers, evs = s.syncWatchers(evs)
   239→		}
   240→		syncDuration := time.Since(st)
   241→
   242→		delayTicker.Reset(watchResyncPeriod)
   243→		// more work pending?
   244→		if unsyncedWatchers != 0 && lastUnsyncedWatchers > unsyncedWatchers {
   245→			// be fair to other store operations by yielding time taken
   246→			delayTicker.Reset(syncDuration)
   247→		}
   248→
   249→		select {
   250→		case <-delayTicker.C:
   251→		case <-s.stopc:
   252→			return
   253→		}
   254→	}
   255→}
   256→
   257→// syncVictimsLoop tries to write precomputed watcher responses to
   258→// watchers that had a blocked watcher channel
   259→func (s *watchableStore) syncVictimsLoop() {
   260→	defer s.wg.Done()
   261→
   262→	for {
   263→		for s.moveVictims() != 0 {
   264→			// try to update all victim watchers
   265→		}
   266→		s.mu.RLock()
   267→		isEmpty := len(s.victims) == 0
   268→		s.mu.RUnlock()
   269→
   270→		var tickc <-chan time.Time
   271→		if !isEmpty {
   272→			tickc = time.After(10 * time.Millisecond)
   273→		}
   274→
   275→		select {
   276→		case <-tickc:
   277→		case <-s.victimc:
   278→		case <-s.stopc:
   279→			return
   280→		}
   281→	}
   282→}
   283→
   284→// moveVictims tries to update watches with already pending event data
   285→func (s *watchableStore) moveVictims() (moved int) {
   286→	s.mu.Lock()
   287→	victims := s.victims
   288→	s.victims = nil
   289→	s.mu.Unlock()
   290→
   291→	var newVictim watcherBatch
   292→	for _, wb := range victims {
   293→		// try to send responses again
   294→		for w, eb := range wb {
   295→			// watcher has observed the store up to, but not including, w.minRev
   296→			rev := w.minRev - 1
   297→			if !w.send(WatchResponse{WatchID: w.id, Events: eb.evs, Revision: rev}) {
   298→				if newVictim == nil {
   299→					newVictim = make(watcherBatch)
   300→				}
   301→				newVictim[w] = eb
   302→				continue
   303→			}
   304→			pendingEventsGauge.Add(float64(len(eb.evs)))
   305→			moved++
   306→		}
   307→
   308→		// assign completed victim watchers to unsync/sync
   309→		s.mu.Lock()
   310→		s.store.revMu.RLock()
   311→		curRev := s.store.currentRev
   312→		for w, eb := range wb {
   313→			if newVictim != nil && newVictim[w] != nil {
   314→				// couldn't send watch response; stays victim
   315→				continue
   316→			}
   317→			w.victim = false
   318→			if eb.moreRev != 0 {
   319→				w.minRev = eb.moreRev
   320→			}
   321→			if w.minRev <= curRev {
   322→				s.unsynced.add(w)
   323→			} else {
   324→				slowWatcherGauge.Dec()
   325→				s.synced.add(w)
   326→			}
   327→		}
   328→		s.store.revMu.RUnlock()
   329→		s.mu.Unlock()
   330→	}
   331→
   332→	if len(newVictim) > 0 {
   333→		s.mu.Lock()
   334→		s.victims = append(s.victims, newVictim)
   335→		s.mu.Unlock()
   336→	}
   337→
   338→	return moved
   339→}
   340→
   341→// syncWatchers syncs unsynced watchers by:
   342→//  1. choose a set of watchers from the unsynced watcher group
   343→//  2. iterate over the set to get the minimum revision and remove compacted watchers
   344→//  3. use minimum revision to get all key-value pairs and send those events to watchers
   345→//  4. remove synced watchers in set from unsynced group and move to synced group
   346→func (s *watchableStore) syncWatchers(evs []mvccpb.Event) (int, []mvccpb.Event) {
   347→	s.mu.Lock()
   348→	defer s.mu.Unlock()
   349→
   350→	if s.unsynced.size() == 0 {
   351→		return 0, []mvccpb.Event{}
   352→	}
   353→
   354→	s.store.revMu.RLock()
   355→	defer s.store.revMu.RUnlock()
   356→
   357→	// in order to find key-value pairs from unsynced watchers, we need to
   358→	// find min revision index, and these revisions can be used to
   359→	// query the backend store of key-value pairs
   360→	curRev := s.store.currentRev
   361→	compactionRev := s.store.compactMainRev
   362→
   363→	wg, minRev := s.unsynced.choose(maxWatchersPerSync, curRev, compactionRev)
   364→	evs = rangeEventsWithReuse(s.store.lg, s.store.b, evs, minRev, curRev+1)
   365→
   366→	victims := make(watcherBatch)
   367→	wb := newWatcherBatch(wg, evs)
   368→	for w := range wg.watchers {
   369→		if w.minRev < compactionRev {
   370→			// Skip the watcher that failed to send compacted watch response due to w.ch is full.
   371→			// Next retry of syncWatchers would try to resend the compacted watch response to w.ch
   372→			continue
   373→		}
   374→		w.minRev = max(curRev+1, w.minRev)
   375→
   376→		eb, ok := wb[w]
   377→		if !ok {
   378→			// bring un-notified watcher to synced
   379→			s.synced.add(w)
   380→			s.unsynced.delete(w)
   381→			continue
   382→		}
   383→
   384→		if eb.moreRev != 0 {
   385→			w.minRev = eb.moreRev
   386→		}
   387→
   388→		if w.send(WatchResponse{WatchID: w.id, Events: eb.evs, Revision: curRev}) {
   389→			pendingEventsGauge.Add(float64(len(eb.evs)))
   390→		} else {
   391→			w.victim = true
   392→		}
   393→
   394→		if w.victim {
   395→			victims[w] = eb
   396→		} else {
   397→			if eb.moreRev != 0 {
   398→				// stay unsynced; more to read
   399→				continue
   400→			}
   401→			s.synced.add(w)
   402→		}
   403→		s.unsynced.delete(w)
   404→	}
   405→	s.addVictim(victims)
   406→
   407→	vsz := 0
   408→	for _, v := range s.victims {
   409→		vsz += len(v)
   410→	}
   411→	slowWatcherGauge.Set(float64(s.unsynced.size() + vsz))
   412→
   413→	return s.unsynced.size(), evs
   414→}
