   416→// rangeEventsWithReuse returns events in range [minRev, maxRev), while reusing already provided events.
   417→func rangeEventsWithReuse(lg *zap.Logger, b backend.Backend, evs []mvccpb.Event, minRev, maxRev int64) []mvccpb.Event {
   418→	if len(evs) == 0 {
   419→		return rangeEvents(lg, b, minRev, maxRev)
   420→	}
   421→	// append from left
   422→	if evs[0].Kv.ModRevision > minRev {
   423→		evs = append(rangeEvents(lg, b, minRev, evs[0].Kv.ModRevision), evs...)
   424→	}
   425→	// cut from left
   426→	prefixIndex := 0
   427→	for prefixIndex < len(evs) && evs[prefixIndex].Kv.ModRevision < minRev {
   428→		prefixIndex++
   429→	}
   430→	evs = evs[prefixIndex:]
   431→
   432→	if len(evs) == 0 {
   433→		return rangeEvents(lg, b, minRev, maxRev)
   434→	}
   435→	// append from right
   436→	if evs[len(evs)-1].Kv.ModRevision+1 < maxRev {
   437→		evs = append(evs, rangeEvents(lg, b, evs[len(evs)-1].Kv.ModRevision+1, maxRev)...)
   438→	}
   439→	// cut from right
   440→	suffixIndex := len(evs) - 1
   441→	for suffixIndex >= 0 && evs[suffixIndex].Kv.ModRevision >= maxRev {
   442→		suffixIndex--
   443→	}
   444→	evs = evs[:suffixIndex+1]
   445→	return evs
   446→}
   447→
   448→// rangeEvents returns events in range [minRev, maxRev).
   449→func rangeEvents(lg *zap.Logger, b backend.Backend, minRev, maxRev int64) []mvccpb.Event {
   450→	if minRev < 0 {
   451→		lg.Warn("Unexpected negative revision range start", zap.Int64("minRev", minRev))
   452→		minRev = 0
   453→	}
   454→	minBytes, maxBytes := NewRevBytes(), NewRevBytes()
   455→	minBytes = RevToBytes(Revision{Main: minRev}, minBytes)
   456→	maxBytes = RevToBytes(Revision{Main: maxRev}, maxBytes)
   457→
   458→	// UnsafeRange returns keys and values. And in boltdb, keys are revisions.
   459→	// values are actual key-value pairs in backend.
   460→	tx := b.ReadTx()
   461→	tx.RLock()
   462→	revs, vs := tx.UnsafeRange(schema.Key, minBytes, maxBytes, 0)
   463→	evs := kvsToEvents(lg, revs, vs)
   464→	// Must unlock after kvsToEvents, because vs (come from boltdb memory) is not deep copy.
   465→	// We can only unlock after Unmarshal, which will do deep copy.
   466→	// Otherwise we will trigger SIGSEGV during boltdb re-mmap.
   467→	tx.RUnlock()
   468→	return evs
   469→}
   470→
   471→// kvsToEvents gets all events for the watchers from all key-value pairs
   472→func kvsToEvents(lg *zap.Logger, revs, vals [][]byte) (evs []mvccpb.Event) {
   473→	for i, v := range vals {
   474→		var kv mvccpb.KeyValue
   475→		if err := kv.Unmarshal(v); err != nil {
   476→			lg.Panic("failed to unmarshal mvccpb.KeyValue", zap.Error(err))
   477→		}
   478→
   479→		ty := mvccpb.Event_PUT
   480→		if isTombstone(revs[i]) {
   481→			ty = mvccpb.Event_DELETE
   482→			// patch in mod revision so watchers won't skip
   483→			kv.ModRevision = BytesToRev(revs[i]).Main
   484→		}
   485→		evs = append(evs, mvccpb.Event{Kv: &kv, Type: ty})
   486→	}
   487→	return evs
   488→}
