    25→// watchBatchMaxRevs is the maximum distinct revisions that
    26→// may be sent to an unsynced watcher at a time. Declared as
    27→// var instead of const for testing purposes.
    28→var watchBatchMaxRevs = 1000
    29→
    30→type eventBatch struct {
    31→	// evs is a batch of revision-ordered events
    32→	evs []mvccpb.Event
    33→	// revs is the minimum unique revisions observed for this batch
    34→	revs int
    35→	// moreRev is first revision with more events following this batch
    36→	moreRev int64
    37→}
    38→
    39→func (eb *eventBatch) add(ev mvccpb.Event) {
    40→	if eb.revs > watchBatchMaxRevs {
    41→		// maxed out batch size
    42→		return
    43→	}
    44→
    45→	if len(eb.evs) == 0 {
    46→		// base case
    47→		eb.revs = 1
    48→		eb.evs = append(eb.evs, ev)
    49→		return
    50→	}
    51→
    52→	// revision accounting
    53→	ebRev := eb.evs[len(eb.evs)-1].Kv.ModRevision
    54→	evRev := ev.Kv.ModRevision
    55→	if evRev > ebRev {
    56→		eb.revs++
    57→		if eb.revs > watchBatchMaxRevs {
    58→			eb.moreRev = evRev
    59→			return
    60→		}
    61→	}
    62→
    63→	eb.evs = append(eb.evs, ev)
    64→}
    65→
    66→type watcherBatch map[*watcher]*eventBatch
    67→
    68→func (wb watcherBatch) add(w *watcher, ev mvccpb.Event) {
    69→	eb := wb[w]
    70→	if eb == nil {
    71→		eb = &eventBatch{}
    72→		wb[w] = eb
    73→	}
    74→	eb.add(ev)
    75→}
